using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _sut = new();

    // ──────────────────────────────────────────────
    // Instantiation
    // ──────────────────────────────────────────────

    [TestMethod]
    public void Constructor_Default_CreatesInstance()
    {
        // Arrange & Act
        var gateway = new PaymentGateway();

        // Assert
        Assert.IsNotNull(gateway);
        Assert.IsInstanceOfType<PaymentGateway>(gateway);
    }

    // ──────────────────────────────────────────────
    // ChargeAsync
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndPositiveAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_valid_123";
        var amount = 49.99m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    [DataRow("tok_abc", 1.00, DisplayName = "MinimalPositiveAmount")]
    [DataRow("tok_xyz", 9999.99, DisplayName = "LargeAmount")]
    [DataRow("tok_special!@#", 100.00, DisplayName = "SpecialCharacterToken")]
    public async Task ChargeAsync_VariousValidInputs_ThrowsNotImplementedException(
        string cardToken, double amountDouble)
    {
        // Arrange
        var amount = (decimal)amountDouble;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_NullCardToken_ThrowsNotImplementedException()
    {
        // Arrange
        string? cardToken = null;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken!, 50.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyCardToken_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = string.Empty;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, 50.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceCardToken_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "   ";

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, 25.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_valid";
        var amount = 0m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_valid";
        var amount = -10.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_MaxDecimalAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_valid";
        var amount = decimal.MaxValue;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    // ──────────────────────────────────────────────
    // RefundAsync
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ThrowsNotImplementedException()
    {
        // Arrange
        var chargeId = "ch_abc123";

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsNotImplementedException()
    {
        // Arrange
        string? chargeId = null;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsNotImplementedException()
    {
        // Arrange
        var chargeId = string.Empty;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    [TestMethod]
    public async Task RefundAsync_WhitespaceChargeId_ThrowsNotImplementedException()
    {
        // Arrange
        var chargeId = "   ";

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    // ──────────────────────────────────────────────
    // ChargeResult record
    // ──────────────────────────────────────────────

    [TestMethod]
    public void ChargeResult_Constructor_SetsProperties()
    {
        // Arrange & Act
        var result = new ChargeResult("ch_001", true);

        // Assert
        Assert.AreEqual("ch_001", result.ChargeId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void ChargeResult_FailedCharge_SetsSuccessToFalse()
    {
        // Arrange & Act
        var result = new ChargeResult("ch_002", false);

        // Assert
        Assert.AreEqual("ch_002", result.ChargeId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public void ChargeResult_Equality_SameValues_AreEqual()
    {
        // Arrange
        var result1 = new ChargeResult("ch_same", true);
        var result2 = new ChargeResult("ch_same", true);

        // Act & Assert
        Assert.AreEqual(result1, result2);
    }

    [TestMethod]
    public void ChargeResult_Equality_DifferentValues_AreNotEqual()
    {
        // Arrange
        var result1 = new ChargeResult("ch_aaa", true);
        var result2 = new ChargeResult("ch_bbb", false);

        // Act & Assert
        Assert.AreNotEqual(result1, result2);
    }

    // ──────────────────────────────────────────────
    // RefundResult record
    // ──────────────────────────────────────────────

    [TestMethod]
    public void RefundResult_Constructor_SetsProperties()
    {
        // Arrange & Act
        var result = new RefundResult("rf_001", true);

        // Assert
        Assert.AreEqual("rf_001", result.RefundId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void RefundResult_FailedRefund_SetsSuccessToFalse()
    {
        // Arrange & Act
        var result = new RefundResult("rf_002", false);

        // Assert
        Assert.AreEqual("rf_002", result.RefundId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public void RefundResult_Equality_SameValues_AreEqual()
    {
        // Arrange
        var result1 = new RefundResult("rf_same", true);
        var result2 = new RefundResult("rf_same", true);

        // Act & Assert
        Assert.AreEqual(result1, result2);
    }

    [TestMethod]
    public void RefundResult_Equality_DifferentValues_AreNotEqual()
    {
        // Arrange
        var result1 = new RefundResult("rf_aaa", true);
        var result2 = new RefundResult("rf_bbb", false);

        // Act & Assert
        Assert.AreNotEqual(result1, result2);
    }
}

